def build_file_payload(attachment)
    content = download_attachment_content(attachment)
    return if content.blank?

    {
      filename: attachment.file.filename.to_s,
      content: content,
      title: attachment.file.filename.to_s
    }
  end

def fire_transition_callbacks(obj, *args)
      from_state = obj.aasm(state_machine.name).current_state
      transition = @valid_transitions[obj.object_id][from_state]
      transition.invoke_success_callbacks(obj, *args) if transition
      @valid_transitions.delete(obj.object_id)
    end

def process_args(event, from_state, *args)
    # If the first arg doesn't respond to to_sym then
    # it isn't a symbol or string so it can't be a state
    # name anyway
    return args unless args.first.respond_to?(:to_sym)
    if event.transitions_from_state(from_state).map(&:to).flatten.include?(args.first)
      return args[1..-1]
    end
    return args
  end

def dependency_digest(finder, stack)
        children.map do |node|
          if stack.include?(node)
            false
          else
            finder.digest_cache[node.name] ||= begin
                                                 stack.push node
                                                 node.digest(finder, stack).tap { stack.pop }
                                               end
          end
        end.join("-")
      end
